record.field:
model.push_to_supabase()
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Push completado',
        'message': 'Datos sincronizados a Supabase. Ve a Historial de Sync para ver detalles.',
        'type': 'success',
        'sticky': False,
    },
}

model.pull_from_supabase()
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Pull completado',
        'message': 'Comandos de Supabase procesados. Ve a Historial de Sync para ver detalles.',
        'type': 'success',
        'sticky': False,
    },
}

result = model.manual_backfill_boms()
env.cr.commit()
msg = (
    'BOMs pusheados: {boms_pushed}. '
    'Tiempo: {elapsed_seconds}s.'
).format(**result)
action = {
    'type': 'ir.actions.client',
    'tag': 'display_notification',
    'params': {
        'title': 'Backfill mrp.bom',
        'message': msg,
        'type': 'success',
        'sticky': True,
    },
}
